// // Synchronous reset circuit that captures an input signal `data_in` on the falling edge of the clock (`clk`). When the reset signal is deasserted, both the delayed input (`data_in_d1`) and the output (`data_out`) are set to a LOW state. Otherwise, `data_in_d1` is updated with the current value of `data_in`, and `data_out` reflects the value of `data_in_d1`. This ensures that the output is synchronized with the clock while handling reset conditions appropriately.
module top_module( clk, data_in, reset, data_out);output data_out; 
  input clk; 
  input data_in; 
  input reset; 
  reg data_in_d1 ; 
  reg data_out ; 
  always @(posedge clk or posedge reset) 
  begin 
  if (reset == 1) data_in_d1 <= 1; 
  else data_in_d1 <= data_in; 
  end 
  always @(posedge clk or posedge reset) 
  begin 
  if (reset == 1) data_out <= 1; 
  else data_out <= data_in_d1; 
  end 
 endmodule
